const config = $node["Set | Import Config"].json;

return [
  {
    json: {
      source_file_name: config.source_file_name,
      source_file_id: config.source_file_id,
      record_type: config.record_type,
      schema_version: config.schema_version,
      inferred_year: Number(config.inferred_year || 2026),
      extracted_item_count: items.length,
      first_item: items[0]?.json || null,
      first_5_items: items.slice(0, 5).map(item => item.json)
    }
  }
];

const output = items[0].json;

if (!output.job) {
  throw new Error(
    'Debug Summary expected output.job. Make sure this node is connected directly after the mission memo normalization node.'
  );
}

return [
  {
    json: {
      ...output,
      debug_summary: {
        success: true,
        import_job_id: output.job.import_job_id,
        mission_id: output.job.mission_id,
        status: output.job.status,
        clean_record_count: output.job.clean_record_count,
        rejected_row_count: output.job.rejected_row_count,
        issue_count: output.job.issue_count,
        warning_count: output.job.warning_count,
        error_count: output.job.error_count,
        processed_sections: output.job.processed_sections,
        first_clean_record: output.records?.[0] || null,
        rejected_rows_sample: output.rejected_rows?.slice(0, 5) || [],
        issues_sample: output.issues?.slice(0, 10) || [],
        message: 'Mission memo transformation completed. No database write performed yet.'
      }
    }
  }
];

const output = items[0].json;

if (!output.job) {
  throw new Error('Missing output.job. Connect this node after the mission memo normalization node or pass-through Debug Summary node.');
}

if (!Array.isArray(output.records)) {
  throw new Error('Missing output.records array.');
}

const cleanRecords = output.records.map(record => ({
  record_id: record.record_id,
  import_job_id: record.import_job_id,
  schema_version: record.schema_version,

  record_type: record.record_type,
  record_category: record.record_category,
  record_subcategory: record.record_subcategory,

  title: record.title,
  start_date: record.start_date,
  end_date: record.end_date,
  month: record.month,
  location: record.location,
  entity: record.entity,
  status: record.status,

  mission_id: record.normalized_payload?.mission_id ?? null,
  document_type: record.normalized_payload?.document_type ?? null,
  memo_date: record.normalized_payload?.memo_date ?? null,
  business_unit: record.normalized_payload?.business_unit ?? null,
  country: record.normalized_payload?.country ?? null,
  classification: record.normalized_payload?.classification ?? null,
  approval_status: record.normalized_payload?.approval_status ?? null,

  participant_name: record.normalized_payload?.participant_name ?? null,
  participant_role: record.normalized_payload?.participant_role ?? null,
  stakeholder_name: record.normalized_payload?.stakeholder_name ?? null,

  day_number: record.normalized_payload?.day_number ?? null,
  agenda_date: record.normalized_payload?.agenda_date ?? null,
  agenda_location: record.normalized_payload?.agenda_location ?? null,
  agenda_description: record.normalized_payload?.agenda_description ?? null,

  use_case_number: record.normalized_payload?.use_case_number ?? null,
  use_case_title: record.normalized_payload?.use_case_title ?? null,
  outcome_number: record.normalized_payload?.outcome_number ?? null,
  outcome_text: record.normalized_payload?.outcome_text ?? null,

  approval_step: record.normalized_payload?.approval_step ?? null,
  signature_status: record.normalized_payload?.signature_status ?? null,

  validation_status: record.validation_status,
  validation_notes: record.validation_notes,

  source_file_name: record.source_file_name,
  source_sheet: record.source_sheet,
  source_row_number: record.source_row_number,

  normalized_payload: record.normalized_payload,
  extra_fields: record.extra_fields
}));

const baseName = String(output.job.source_file_name || 'mission_memo_import')
  .replace(/\.[^.]+$/, '')
  .replace(/[^\w.-]+/g, '_');

return [
  {
    json: {
      file_type: 'clean_records',
      file_name: `${baseName}_clean_mission_records.json`,
      data: cleanRecords
    }
  },
  {
    json: {
      file_type: 'rejected_rows',
      file_name: `${baseName}_rejected_rows.json`,
      data: output.rejected_rows || []
    }
  },
  {
    json: {
      file_type: 'issues',
      file_name: `${baseName}_import_issues.json`,
      data: output.issues || []
    }
  },
  {
    json: {
      file_type: 'full_import_payload',
      file_name: `${baseName}_full_import_payload.json`,
      data: output
    }
  }
];

const item = items[0].json;

if (item.file_type !== 'clean_records') {
  throw new Error(`Expected file_type "clean_records", received "${item.file_type}".`);
}

if (!Array.isArray(item.data)) {
  throw new Error('Expected item.data to be an array of clean mission records.');
}

const rows = item.data;

const preferredColumns = [
  'record_id',
  'import_job_id',
  'schema_version',

  'record_type',
  'record_category',
  'record_subcategory',

  'title',
  'start_date',
  'end_date',
  'month',
  'location',
  'entity',
  'status',

  'mission_id',
  'document_type',
  'memo_date',
  'business_unit',
  'country',
  'classification',
  'approval_status',

  'participant_name',
  'participant_role',
  'stakeholder_name',

  'day_number',
  'agenda_date',
  'agenda_location',
  'agenda_description',

  'use_case_number',
  'use_case_title',
  'outcome_number',
  'outcome_text',

  'approval_step',
  'signature_status',

  'validation_status',
  'validation_notes',

  'source_file_name',
  'source_sheet',
  'source_row_number',

  'normalized_payload',
  'extra_fields'
];

const allColumns = Array.from(
  new Set(rows.flatMap(row => Object.keys(row)))
);

const columns = [
  ...preferredColumns.filter(col => allColumns.includes(col)),
  ...allColumns.filter(col => !preferredColumns.includes(col))
];

function csvEscape(value) {
  if (value === null || value === undefined) return '';

  const s = typeof value === 'object' ? JSON.stringify(value) : String(value);

  if (/[",\n\r]/.test(s)) {
    return `"${s.replace(/"/g, '""')}"`;
  }

  return s;
}

const lines = [];

lines.push(columns.map(csvEscape).join(','));

for (const row of rows) {
  lines.push(columns.map(col => csvEscape(row[col])).join(','));
}

const csv = '\uFEFF' + lines.join('\r\n');

const baseName = String(item.file_name || 'clean_mission_records.json')
  .replace(/\.json$/i, '')
  .replace(/[^\w.-]+/g, '_');

const fileName = `${baseName}.csv`;

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(csv, 'utf8'),
  fileName,
  'text/csv'
);

return [
  {
    json: {
      file_type: 'clean_records_csv',
      file_name: fileName,
      row_count: rows.length,
      column_count: columns.length,
      columns
    },
    binary: {
      data: binaryData
    }
  }
];

const config = $node["Set | Import Config"].json;

const schemaVersion = config.schema_version || 'canonical-records-v1';
const defaultRecordType = config.record_type || 'international_mission';
const sourceFileId = config.source_file_id || null;
const sourceFileName = config.source_file_name || 'unknown_mission_memo';
const year = Number(config.year || 2026);
const documentType = config.document_type || 'mission_approval_memo';
const classificationFromConfig = config.document_classification || null;

const importJobId = `mission_imp_${Date.now()}`;

const MONTHS = {
  jan: 1, january: 1,
  feb: 2, february: 2,
  mar: 3, march: 3,
  apr: 4, april: 4,
  may: 5,
  jun: 6, june: 6,
  jul: 7, july: 7,
  aug: 8, august: 8,
  sep: 9, sept: 9, september: 9,
  oct: 10, october: 10,
  nov: 11, november: 11,
  dec: 12, december: 12
};

const MONTH_LABELS = {
  1: 'January',
  2: 'February',
  3: 'March',
  4: 'April',
  5: 'May',
  6: 'June',
  7: 'July',
  8: 'August',
  9: 'September',
  10: 'October',
  11: 'November',
  12: 'December'
};

function clean(value) {
  if (value === null || value === undefined) return null;

  const s = String(value)
    .replace(/\u00a0/g, ' ')
    .replace(/[–—]/g, '-')
    .replace(/\r/g, '\n')
    .trim()
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n');

  if (!s) return null;

  const lower = s.toLowerCase();
  if (['-', '—', 'n/a', 'na', 'null', 'undefined'].includes(lower)) return null;

  return s;
}

function oneLine(value) {
  return String(value || '')
    .replace(/\u00a0/g, ' ')
    .replace(/[–—]/g, '-')
    .replace(/\r/g, '\n')
    .replace(/\n+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function norm(value) {
  return String(value ?? '')
    .replace(/\u00a0/g, ' ')
    .replace(/[–—]/g, '-')
    .trim()
    .toLowerCase()
    .replace(/&/g, ' and ')
    .replace(/[_\-./:;()\[\]#]+/g, ' ')
    .replace(/[^\p{L}\p{N}\s]+/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function hash(input, length = 16) {
  let h = 2166136261;
  const s = String(input ?? '');

  for (let i = 0; i < s.length; i++) {
    h ^= s.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }

  const hex = (h >>> 0).toString(16).padStart(8, '0');
  return (hex + hex + hex + hex).slice(0, length);
}

function pad2(n) {
  return String(n).padStart(2, '0');
}

function isoDate(y, m, d) {
  const yearValue = Number(y);
  const monthValue = Number(m);
  const dayValue = Number(d);

  if (!yearValue || !monthValue || !dayValue) return null;

  const date = new Date(Date.UTC(yearValue, monthValue - 1, dayValue));

  if (
    date.getUTCFullYear() !== yearValue ||
    date.getUTCMonth() !== monthValue - 1 ||
    date.getUTCDate() !== dayValue
  ) {
    return null;
  }

  return `${yearValue}-${pad2(monthValue)}-${pad2(dayValue)}`;
}

function monthNumber(value) {
  const key = norm(value);
  return MONTHS[key] || null;
}

function monthNameFromIso(iso) {
  if (!iso) return null;
  const m = Number(String(iso).slice(5, 7));
  return MONTH_LABELS[m] || null;
}

function parseTextDate(value, defaultYear = year) {
  const s = oneLine(value);
  if (!s) return null;

  let m;

  // 13 May 2026
  m = s.match(/(\d{1,2})\s*(?:st|nd|rd|th)?\s+([A-Za-z]+)\s+(\d{4})/i);
  if (m) {
    const mo = monthNumber(m[2]);
    if (mo) return isoDate(Number(m[3]), mo, Number(m[1]));
  }

  // May 13, 2026
  m = s.match(/([A-Za-z]+)\s+(\d{1,2})\s*,?\s+(\d{4})/i);
  if (m) {
    const mo = monthNumber(m[1]);
    if (mo) return isoDate(Number(m[3]), mo, Number(m[2]));
  }

  // 19th May, with default year
  m = s.match(/(\d{1,2})\s*(?:st|nd|rd|th)?\s+([A-Za-z]+)/i);
  if (m) {
    const mo = monthNumber(m[2]);
    if (mo) return isoDate(defaultYear, mo, Number(m[1]));
  }

  return null;
}

function parseDateRangeFromSubject(subject) {
  const s = oneLine(subject);

  // (May 19-21, 2026)
  const m = s.match(/\(([A-Za-z]+)\s+(\d{1,2})\s*-\s*(\d{1,2})\s*,\s*(\d{4})\)/i);

  if (!m) {
    return {
      start_date: null,
      end_date: null,
      warning: 'Could not parse mission date range from subject.'
    };
  }

  const mo = monthNumber(m[1]);
  if (!mo) {
    return {
      start_date: null,
      end_date: null,
      warning: 'Could not parse mission month from subject.'
    };
  }

  return {
    start_date: isoDate(Number(m[4]), mo, Number(m[2])),
    end_date: isoDate(Number(m[4]), mo, Number(m[3])),
    warning: null
  };
}

function collectStrings(value, output = []) {
  if (value === null || value === undefined) return output;

  if (typeof value === 'string') {
    if (value.trim().length > 20) output.push(value);
    return output;
  }

  if (Array.isArray(value)) {
    for (const v of value) collectStrings(v, output);
    return output;
  }

  if (typeof value === 'object') {
    for (const v of Object.values(value)) collectStrings(v, output);
    return output;
  }

  return output;
}

function captureBetween(text, startPattern, endPattern) {
  const re = new RegExp(`${startPattern}\\s+([\\s\\S]*?)\\s+(?=${endPattern})`, 'i');
  const m = text.match(re);
  return clean(m?.[1]) || null;
}

function addIssue(issues, base, severity, issueCode, fieldName, message, originalValue = null, normalizedValue = null) {
  issues.push({
    import_job_id: importJobId,
    severity,
    issue_code: issueCode,
    field_name: fieldName,
    source_file_id: sourceFileId,
    source_file_name: sourceFileName,
    source_sheet: base.source_sheet || 'Approval Memo PDF',
    source_row_number: base.source_row_number || null,
    original_value: originalValue === null || originalValue === undefined ? null : String(originalValue),
    normalized_value: normalizedValue === null || normalizedValue === undefined ? null : String(normalizedValue),
    message
  });
}

function makeRecord({
  record_type,
  record_category,
  record_subcategory = null,
  title,
  start_date = null,
  end_date = null,
  month = null,
  location = null,
  entity = null,
  status = 'Unknown',
  source_row_number = null,
  validation_status = 'valid',
  validation_notes = null,
  raw_row = {},
  normalized_payload = {},
  extra_fields = {}
}) {
  return {
    record_id: `rec_${hash([
      importJobId,
      record_type,
      record_category,
      record_subcategory,
      title,
      start_date,
      source_row_number
    ].join('|'), 24)}`,
    import_job_id: importJobId,
    schema_version: schemaVersion,

    record_type,
    record_category,
    record_subcategory,

    title,
    start_date,
    end_date,
    month,

    location,
    website: null,
    entity,
    ga: null,

    attendance_format: null,
    sponsoring_level: null,
    contact_person: null,
    project_owner: null,
    status,

    source_file_id: sourceFileId,
    source_file_name: sourceFileName,
    source_sheet: 'Approval Memo PDF',
    source_row_number,

    validation_status,
    validation_notes,

    raw_row,
    normalized_payload,
    extra_fields
  };
}

function splitBullets(text) {
  if (!text) return [];

  return String(text)
    .split(/[●•]\s*/g)
    .map(v => clean(v))
    .filter(Boolean);
}

function extractParticipants(participantsText) {
  const result = {
    internal_participants: [],
    external_stakeholders: []
  };

  const bullets = splitBullets(participantsText);

  for (const bullet of bullets) {
    if (/indonesia delegation/i.test(bullet)) continue;

    const m = bullet.match(/^(.+?)\s*-\s*(.+)$/);

    if (m) {
      result.internal_participants.push({
        name: clean(m[1]),
        role: clean(m[2]),
        delegation_group: 'Research Council / Nabat'
      });
    }
  }

  const indonesiaMatch = oneLine(participantsText).match(/Indonesia Delegation:\s*(.*?)(?=\s*3 Program|\s*$)/i);

  if (indonesiaMatch) {
    const stakeholderText = indonesiaMatch[1];
    const parts = stakeholderText
      .split(/,\s+|\s+and\s+/i)
      .map(v => clean(v))
      .filter(Boolean);

    for (const p of parts) {
      result.external_stakeholders.push({
        name: p,
        stakeholder_group: 'Indonesia Delegation'
      });
    }
  }

  return result;
}

function extractAgendaItems(text) {
  const agendaText = captureBetween(text, 'Tentative Agenda:', 'Expected Outcomes|4 Budget|Budget') || '';
  const result = [];

  const re = /Day\s+(\d+),\s*(\d{1,2})\s*(?:st|nd|rd|th)?\s+([A-Za-z]+)\s*,\s*([^:]+):\s*([\s\S]*?)(?=\s*Day\s+\d+,|\s*$)/gi;

  for (const m of agendaText.matchAll(re)) {
    const dayNumber = Number(m[1]);
    const date = parseTextDate(`${m[2]} ${m[3]} ${year}`);
    const location = clean(m[4]);
    const description = clean(m[5]);

    result.push({
      day_number: dayNumber,
      date,
      location,
      description,
      title: `Day ${dayNumber}: ${location}`
    });
  }

  return result;
}

function extractUseCases(programText) {
  const result = [];
  if (!programText) return result;

  const re = /Use Case\s+(\d+)\s*-\s*([^:]+):\s*([\s\S]*?)(?=\s*Use Case\s+\d+\s*-|\s*Note:|\s*Tentative Agenda:|\s*$)/gi;

  for (const m of programText.matchAll(re)) {
    result.push({
      use_case_number: Number(m[1]),
      title: clean(m[2]),
      description: clean(m[3])
    });
  }

  return result;
}

function extractExpectedOutcomes(text) {
  const expectedText = captureBetween(text, 'Expected Outcomes', '4 Budget|Budget') || '';
  return splitBullets(expectedText);
}

function extractVerifiedSignatories(text) {
  const verifiedText = captureBetween(text, 'Verified Signature', 'Approved by') || '';

  const result = [];
  const normalized = oneLine(verifiedText);

  const re = /([A-ZÀ-ỿ][A-Za-zÀ-ỿ.'\s]+?)\s*-\s*([\s\S]*?)(?=\s+[A-ZÀ-ỿ][A-Za-zÀ-ỿ.'\s]+?\s*-|\s*$)/g;

  for (const m of normalized.matchAll(re)) {
    const name = clean(m[1]);
    const role = clean(m[2]);

    if (name && role) {
      result.push({
        name,
        role
      });
    }
  }

  return result;
}

const extractedText = items
  .flatMap(item => collectStrings(item.json))
  .join('\n');

const text = clean(extractedText);
const flatText = oneLine(text);

const records = [];
const rejected_rows = [];
const issues = [];

if (!text || text.length < 50) {
  addIssue(
    issues,
    { source_sheet: 'Approval Memo PDF' },
    'error',
    'pdf_text_not_extracted',
    null,
    'No usable text was extracted from the memo PDF. This may require OCR or a DOCX/source-file extraction path.'
  );

  return [
    {
      json: {
        job: {
          import_job_id: importJobId,
          schema_version: schemaVersion,
          status: 'failed_no_text',
          source_system: 'google_drive_pdf_mission_memo',
          source_file_id: sourceFileId,
          source_file_name: sourceFileName,
          record_type: defaultRecordType,
          clean_record_count: 0,
          rejected_row_count: 0,
          issue_count: issues.length,
          warning_count: issues.filter(i => i.severity === 'warning').length,
          error_count: issues.filter(i => i.severity === 'error').length
        },
        records,
        rejected_rows,
        issues
      }
    }
  ];
}

const memoDateRaw = flatText.match(/Memo Date\s+(\d{1,2}\s+[A-Za-z]+\s+\d{4})/i)?.[1] || null;
const memoDate = parseTextDate(memoDateRaw);

const entity = captureBetween(flatText, 'Entity', 'Business Unit') || null;
const businessUnit = captureBetween(flatText, 'Business Unit', 'Subject') || null;
const subject = captureBetween(flatText, 'Subject', 'Attachments') || null;
const attachments = captureBetween(flatText, 'Attachments', '# Terms|1 Overview') || null;
const overview = captureBetween(flatText, '1 Overview', '2 Participants') || null;
const participantsText = captureBetween(flatText, '2 Participants', '3 Program') || null;
const programText = captureBetween(flatText, '3 Program', '4 Budget|Budget') || null;
const budget = captureBetween(flatText, '4 Budget|Budget', 'Verified Signature|Approved by') || null;

const location = programText?.match(/Location:\s*(.*?)\s+Proposed/i)?.[1]
  ? clean(programText.match(/Location:\s*(.*?)\s+Proposed/i)[1])
  : null;

const dateRange = parseDateRangeFromSubject(subject || '');
const startDate = dateRange.start_date;
const endDate = dateRange.end_date;

const classification =
  classificationFromConfig ||
  (/confidential/i.test(flatText) ? 'Confidential' : null);

const country = /indonesia/i.test(flatText) ? 'Indonesia' : null;
const missionId = `MIS-${hash([subject, startDate, endDate, country].join('|'), 10).toUpperCase()}`;

const participants = extractParticipants(participantsText);
const agendaItems = extractAgendaItems(flatText);
const useCases = extractUseCases(programText);
const expectedOutcomes = extractExpectedOutcomes(flatText);
const verifiedSignatories = extractVerifiedSignatories(flatText);

const approvedSection = flatText.match(/Approved by\s+_*\s*(.*?)(?:Document Classified|$)/i)?.[1] || null;
const approvalName = approvedSection
  ? clean(approvedSection.replace(/Director General/i, '').trim())
  : null;

if (classification) {
  addIssue(
    issues,
    { source_row_number: 1 },
    'warning',
    'document_marked_confidential',
    'classification',
    `Document is marked or configured as ${classification}.`,
    classification,
    classification
  );
}

if (dateRange.warning) {
  addIssue(
    issues,
    { source_row_number: 1 },
    'warning',
    'mission_dates_not_parsed',
    'subject',
    dateRange.warning,
    subject
  );
} else {
  addIssue(
    issues,
    { source_row_number: 1 },
    'info',
    'mission_dates_inferred_from_subject',
    'subject',
    'Mission start and end dates were inferred from the memo subject.',
    subject,
    `${startDate} to ${endDate}`
  );
}

if (/pending scope finalization|pending scope|effort estimation/i.test(budget || '')) {
  addIssue(
    issues,
    { source_row_number: 2 },
    'warning',
    'budget_not_finalized',
    'budget',
    'Budget text indicates that demo budget is pending scope finalization or effort estimation.',
    budget
  );
}

if (/subject to workshop outputs/i.test(programText || '')) {
  addIssue(
    issues,
    { source_row_number: 2 },
    'warning',
    'scope_subject_to_workshop_outputs',
    'program',
    'Final scope of work is subject to workshop outputs.',
    'Final scope of work is subject to workshop outputs.'
  );
}

if (participants.internal_participants.length || participants.external_stakeholders.length) {
  addIssue(
    issues,
    { source_row_number: 1 },
    'info',
    'participants_extracted_from_free_text',
    'participants',
    'Participants and stakeholders were extracted from free-text memo content.',
    participantsText,
    `${participants.internal_participants.length} internal participants; ${participants.external_stakeholders.length} external stakeholders`
  );
}

addIssue(
  issues,
  { source_row_number: 2 },
  'warning',
  'approval_signature_not_machine_verified',
  'approval',
  'Approval signature presence cannot be reliably verified from extracted PDF text. Manual confirmation is recommended.',
  approvedSection
);

const parentValidationNotes = [];
if (!subject) parentValidationNotes.push('Missing memo subject.');
if (!startDate || !endDate) parentValidationNotes.push('Mission dates could not be parsed.');
if (!memoDate) parentValidationNotes.push('Memo date could not be parsed.');
if (classification) parentValidationNotes.push(`Document classification: ${classification}.`);
if (/pending/i.test(budget || '')) parentValidationNotes.push('Budget not finalized.');
if (/subject to workshop outputs/i.test(programText || '')) parentValidationNotes.push('Scope subject to workshop outputs.');
parentValidationNotes.push('Approval signature requires manual confirmation.');

const parentStatus = 'submitted_for_approval';

const parentRecord = makeRecord({
  record_type: 'international_mission',
  record_category: 'Mission Approval Memo',
  record_subcategory: country,
  title: subject || 'Untitled international mission',
  start_date: startDate,
  end_date: endDate,
  month: monthNameFromIso(startDate),
  location,
  entity,
  status: parentStatus,
  source_row_number: 1,
  validation_status: parentValidationNotes.length ? 'valid_with_warnings' : 'valid',
  validation_notes: parentValidationNotes.join(' '),
  raw_row: {
    memo_text: text
  },
  normalized_payload: {
    mission_id: missionId,
    document_type: documentType,
    memo_date: memoDate,
    entity,
    business_unit: businessUnit,
    subject,
    country,
    location,
    attachments,
    overview,
    budget,
    approval_status: parentStatus,
    classification,
    participant_count: participants.internal_participants.length,
    external_stakeholder_count: participants.external_stakeholders.length,
    agenda_item_count: agendaItems.length,
    use_case_count: useCases.length,
    expected_outcome_count: expectedOutcomes.length
  },
  extra_fields: {
    source_format: 'pdf',
    approved_by_text: approvedSection,
    approved_by_name: approvalName,
    verified_signatories: verifiedSignatories
  }
});

if (!parentRecord.title || !parentRecord.start_date) {
  rejected_rows.push({
    import_job_id: importJobId,
    source_file_id: sourceFileId,
    source_file_name: sourceFileName,
    source_sheet: 'Approval Memo PDF',
    source_row_number: 1,
    rejection_reason: 'Mission title and start_date are required.',
    errors: [
      {
        field: 'title/start_date',
        code: 'required_field_missing',
        message: 'Mission title and start_date are required.'
      }
    ],
    raw_row: {
      memo_text: text
    }
  });
} else {
  records.push(parentRecord);
}

let rowNumber = 10;

for (const agenda of agendaItems) {
  records.push(makeRecord({
    record_type: 'mission_agenda_item',
    record_category: missionId,
    record_subcategory: `Day ${agenda.day_number}`,
    title: agenda.title,
    start_date: agenda.date,
    end_date: agenda.date,
    month: monthNameFromIso(agenda.date),
    location: agenda.location,
    entity,
    status: 'planned',
    source_row_number: rowNumber++,
    validation_status: agenda.date ? 'valid' : 'valid_with_warnings',
    validation_notes: agenda.date ? null : 'Agenda date could not be parsed.',
    raw_row: agenda,
    normalized_payload: {
      mission_id: missionId,
      day_number: agenda.day_number,
      agenda_date: agenda.date,
      agenda_location: agenda.location,
      agenda_description: agenda.description
    },
    extra_fields: {}
  }));
}

for (const person of participants.internal_participants) {
  records.push(makeRecord({
    record_type: 'mission_participant',
    record_category: missionId,
    record_subcategory: person.delegation_group,
    title: person.name,
    start_date: startDate,
    end_date: endDate,
    month: monthNameFromIso(startDate),
    location,
    entity,
    status: 'planned',
    source_row_number: rowNumber++,
    raw_row: person,
    normalized_payload: {
      mission_id: missionId,
      participant_name: person.name,
      participant_role: person.role,
      delegation_group: person.delegation_group,
      participant_type: 'internal'
    },
    extra_fields: {}
  }));
}

for (const stakeholder of participants.external_stakeholders) {
  records.push(makeRecord({
    record_type: 'mission_stakeholder',
    record_category: missionId,
    record_subcategory: stakeholder.stakeholder_group,
    title: stakeholder.name,
    start_date: startDate,
    end_date: endDate,
    month: monthNameFromIso(startDate),
    location,
    entity: stakeholder.name,
    status: 'planned',
    source_row_number: rowNumber++,
    raw_row: stakeholder,
    normalized_payload: {
      mission_id: missionId,
      stakeholder_name: stakeholder.name,
      stakeholder_group: stakeholder.stakeholder_group,
      stakeholder_type: 'external'
    },
    extra_fields: {}
  }));
}

for (const useCase of useCases) {
  records.push(makeRecord({
    record_type: 'mission_use_case',
    record_category: missionId,
    record_subcategory: `Use Case ${useCase.use_case_number}`,
    title: useCase.title,
    start_date: startDate,
    end_date: endDate,
    month: monthNameFromIso(startDate),
    location,
    entity,
    status: 'proposed',
    source_row_number: rowNumber++,
    raw_row: useCase,
    normalized_payload: {
      mission_id: missionId,
      use_case_number: useCase.use_case_number,
      use_case_title: useCase.title,
      use_case_description: useCase.description
    },
    extra_fields: {}
  }));
}

for (let i = 0; i < expectedOutcomes.length; i++) {
  const outcome = expectedOutcomes[i];

  records.push(makeRecord({
    record_type: 'mission_expected_outcome',
    record_category: missionId,
    record_subcategory: `Outcome ${i + 1}`,
    title: outcome.slice(0, 120),
    start_date: startDate,
    end_date: endDate,
    month: monthNameFromIso(startDate),
    location,
    entity,
    status: 'expected',
    source_row_number: rowNumber++,
    raw_row: {
      outcome
    },
    normalized_payload: {
      mission_id: missionId,
      outcome_number: i + 1,
      outcome_text: outcome
    },
    extra_fields: {}
  }));
}

for (const verifier of verifiedSignatories) {
  records.push(makeRecord({
    record_type: 'mission_approval_step',
    record_category: missionId,
    record_subcategory: 'Verified',
    title: verifier.name,
    start_date: memoDate,
    end_date: memoDate,
    month: monthNameFromIso(memoDate),
    location: null,
    entity,
    status: 'verified_listed',
    source_row_number: rowNumber++,
    raw_row: verifier,
    normalized_payload: {
      mission_id: missionId,
      approval_step: 'verified',
      person_name: verifier.name,
      person_role: verifier.role,
      signature_status: 'listed_not_machine_verified'
    },
    extra_fields: {}
  }));
}

if (approvalName || approvedSection) {
  records.push(makeRecord({
    record_type: 'mission_approval_step',
    record_category: missionId,
    record_subcategory: 'Approved by',
    title: approvalName || 'Approver listed',
    start_date: memoDate,
    end_date: memoDate,
    month: monthNameFromIso(memoDate),
    location: null,
    entity,
    status: 'pending_signature_or_manual_confirmation',
    source_row_number: rowNumber++,
    validation_status: 'valid_with_warnings',
    validation_notes: 'Approval signature not machine verified from PDF text.',
    raw_row: {
      approved_by_text: approvedSection
    },
    normalized_payload: {
      mission_id: missionId,
      approval_step: 'approved_by',
      approved_by_name: approvalName,
      approved_by_text: approvedSection,
      signature_status: 'not_machine_verified'
    },
    extra_fields: {}
  }));
}

const warningCount = issues.filter(issue => issue.severity === 'warning').length;
const errorCount = issues.filter(issue => issue.severity === 'error').length;

const job = {
  import_job_id: importJobId,
  schema_version: schemaVersion,
  status:
    errorCount > 0 && records.length === 0
      ? 'failed_no_clean_records'
      : warningCount || errorCount
        ? 'completed_with_issues'
        : 'completed',
  source_system: 'google_drive_pdf_mission_memo',
  source_file_id: sourceFileId,
  source_file_name: sourceFileName,
  record_type: defaultRecordType,
  document_type: documentType,
  year,
  total_records: records.length + rejected_rows.length,
  clean_record_count: records.length,
  rejected_row_count: rejected_rows.length,
  issue_count: issues.length,
  warning_count: warningCount,
  error_count: errorCount,
  processed_sections: [
    'memo_metadata',
    'overview',
    'participants',
    'program',
    'agenda',
    'expected_outcomes',
    'budget',
    'approval'
  ],
  mission_id: missionId
};

return [
  {
    json: {
      job,
      records,
      rejected_rows,
      issues
    }
  }
];
